const body = $json.body || $json;

function cleanPhone(phone) {
  let p = String(phone || '').replace(/[^0-9]/g, '');
  if (p.startsWith('0')) p = '62' + p.slice(1);
  if (!p.startsWith('62')) p = '62' + p;
  return p;
}

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d.toISOString().slice(0, 10);
}

const service = String(body.jenis_layanan || '').toLowerCase();
let reminderDays = 60;
if (service.includes('oli')) reminderDays = 30;
if (service.includes('ban')) reminderDays = 90;
if (service.includes('service')) reminderDays = 60;

const txDate = body.tanggal_transaksi || new Date().toISOString().slice(0, 10);

return [{
  json: {
    customer_id: body.customer_id || `${cleanPhone(body.nomor_wa)}-${String(body.plat_nomor || '').replace(/\s+/g, '').toUpperCase()}`,
    nama: String(body.nama || '').trim(),
    nomor_wa: cleanPhone(body.nomor_wa),
    plat_nomor: String(body.plat_nomor || '').trim().toUpperCase(),
    jenis_layanan: String(body.jenis_layanan || '').trim(),
    tanggal_transaksi: txDate,
    nominal_transaksi: Number(body.nominal_transaksi || 0),
    reminder_days: reminderDays,
    next_reminder_date: addDays(txDate, reminderDays),
    reminder_stage: 'none',
    last_message_sent_at: '',
    status: 'active',
    consent_whatsapp: String(body.consent_whatsapp || 'yes').toLowerCase(),
    notes: body.notes || ''
  }
}];

const today = new Date().toISOString().slice(0, 10);
const output = [];

for (const item of items) {
  const r = item.json;
  if (String(r.consent_whatsapp || '').toLowerCase() !== 'yes') continue;
  if (String(r.status || '').toLowerCase() !== 'active') continue;

  const stage = String(r.reminder_stage || 'none');
  const next = String(r.next_reminder_date || '');
  const lastSent = String(r.last_message_sent_at || '').slice(0, 10);

  if (next && next <= today && stage === 'none') {
    output.push({ json: { ...r, message_type: 'reminder' } });
    continue;
  }

  if (stage === 'reminder_30_sent' && lastSent) {
    const d = new Date(lastSent);
    d.setDate(d.getDate() + 7);
    const discountDate = d.toISOString().slice(0, 10);
    if (discountDate <= today) output.push({ json: { ...r, message_type: 'discount' } });
  }
}

return output;

return items.map(item => {
  const r = item.json;
  const shop = $env.SHOP_NAME || 'Bengkel Kami';
  const promoEnd = new Date();
  promoEnd.setDate(promoEnd.getDate() + 7);

  let message;
  let nextStage;

  if (r.message_type === 'discount') {
    message = `Halo ${r.nama}, promo khusus untuk motor ${r.plat_nomor}. Dapat diskon 10% untuk ganti oli/service ringan di ${shop} sampai ${promoEnd.toISOString().slice(0, 10)}. Balas pesan ini untuk booking.`;
    nextStage = 'discount_7d_sent';
  } else {
    message = `Halo ${r.nama}, kami dari ${shop}. Motor dengan plat ${r.plat_nomor} terakhir melakukan ${r.jenis_layanan} pada ${r.tanggal_transaksi}. Sudah waktunya cek kondisi oli/ban agar motor tetap aman dipakai. Balas pesan ini untuk booking.`;
    nextStage = 'reminder_30_sent';
  }

  return { json: { ...r, wa_target: r.nomor_wa, wa_message: message, next_stage: nextStage, sent_at: new Date().toISOString() } };
});
